SELECT COUNT(*) AS total_nodes
FROM network_nodes
WHERE network_id = 1;

SELECT network_id, COUNT(node_id) AS node_count
FROM network_nodes
GROUP BY network_id;

SELECT property_value
FROM network_properties
WHERE network_id = 1 AND property_name = 'number of nodes';

SELECT MAX(metric_value) AS max_modularity
FROM community_metrics
WHERE metric_name = 'modularity';

SELECT COUNT(run_id) AS run_count
FROM community_detection_runs
WHERE network_id = 1;

SELECT MAX(similarity_score) AS highest_similarity_score
  FROM community_similarity
  WHERE network_id1 = network_id2;

SELECT AVG(similarity_score) AS average_similarity
FROM node_similarity
WHERE network_id1 = 1 OR network_id2 = 1;

SELECT COUNT(node_id) AS node_count
FROM network_nodes
WHERE network_id = (SELECT network_id FROM networks WHERE network_name = 'Social Network A');

SELECT AVG(metric_value) AS average_modularity
FROM community_metrics
WHERE metric_name = 'modularity';
